/**
 * Regression test for Bug 2 — "resumed reviewer terminated before reminder
 * is acted on".
 *
 * After a server restart, the verification harness calls `_tryResumeFromSession`.
 * If the reviewer session is currently `idle`, the harness dispatches a
 * reminder prompt and races `resultPromise` against `waitForIdle(120s)`.
 *
 * Pre-fix: `waitForIdle` resolved synchronously because the session was
 * already idle, and `rpcClient.prompt()` is fire-and-forget — the session
 * had not yet transitioned to `streaming`. The race resolved `idle` instantly,
 * the harness declared failure, and `terminateSession` ran in the `finally`
 * block ~46ms after the reminder. The reviewer never had a chance to respond.
 *
 * Fix: `await waitForStreaming(sessionId, 10_000).catch(() => {})` between the
 * reminder dispatch and the race, so the race only starts once the agent has
 * begun a new turn (or 10s have elapsed — fall through, real failure).
 *
 * This test reproduces the exact reminder-then-race fragment using a fake
 * SessionManager. Without the `waitForStreaming` await, the race resolves
 * `idle` ~immediately (well under the 1-second SLA the test asserts).
 */
import { describe, it } from "vitest";
import assert from "node:assert/strict";
import fs from "node:fs";
import os from "node:os";
import path from "node:path";
import { initAuthorSidecarDir } from "../../src/server/agent/author-sidecar.ts";
import { VerificationHarness, VERIFICATION_RESTART_RESUME_PROMPT, VERIFICATION_RESULT_REMINDER } from "../../src/server/agent/verification-harness.ts";

const SYSTEM_MODEL_PREFIX = "[System]: ";

function modelFacingSystemPrompt(baseText: string): string {
	return `${SYSTEM_MODEL_PREFIX}${baseText}`;
}

function assertSingleSystemPrefix(piText: string, context: string): string {
	assert.ok(piText.startsWith(SYSTEM_MODEL_PREFIX), `${context}: provider text must start with the system prefix`);
	const baseText = piText.slice(SYSTEM_MODEL_PREFIX.length);
	assert.ok(!baseText.startsWith(SYSTEM_MODEL_PREFIX), `${context}: provider text must contain exactly one leading system prefix`);
	return baseText;
}

function initVerificationAuthorSidecar(stateDir: string): void {
	initAuthorSidecarDir(stateDir, {
		secretsDir: path.join(stateDir, "private-secrets"),
		hmacKey: Buffer.alloc(32, 0x36),
	});
}

/**
 * `SessionManager` transitively pulls in flexsearch (via search-service),
 * which doesn't import cleanly under tsx in this test runner. Instead we
 * port the small `waitForStreaming` / `waitForIdle` helpers verbatim and
 * exercise them with the same `FakeSession` shape. The ported helpers are
 * byte-equivalent to the implementations in src/server/agent/session-manager.ts
 * — kept in sync via review (any structural divergence will be caught by
 * `npm run check`, since the production code is the only consumer).
 */

/** Minimal stand-in for a real session: emits agent_start / agent_end. */
class FakeSession {
	id: string;
	status: "idle" | "streaming" = "idle";
	private cbs: Array<(e: any) => void> = [];
	rpcClient = {
		prompt: async () => { /* fire-and-forget — does NOT change status */ },
		onEvent: (cb: (e: any) => void) => {
			this.cbs.push(cb);
			return () => {
				const i = this.cbs.indexOf(cb);
				if (i >= 0) this.cbs.splice(i, 1);
			};
		},
	};
	constructor(id: string) { this.id = id; }
	fire(event: any) { for (const cb of [...this.cbs]) cb(event); }
	startTurn() { this.status = "streaming"; this.fire({ type: "agent_start" }); }
	endTurn() { this.status = "idle"; this.fire({ type: "agent_end" }); }
}

/** Mirror of SessionManager.waitForStreaming (the helper under test). */
function waitForStreaming(session: FakeSession, timeoutMs: number): Promise<void> {
	if (session.status === "streaming") return Promise.resolve();
	return new Promise<void>((resolve, reject) => {
		const timer = setTimeout(() => {
			unsub();
			reject(new Error(`Timeout waiting for session ${session.id} to start streaming`));
		}, timeoutMs);
		const unsub = session.rpcClient.onEvent((event: any) => {
			if (event.type === "agent_start") {
				clearTimeout(timer);
				unsub();
				resolve();
			}
		});
	});
}

/** Mirror of SessionManager.waitForIdle. */
function waitForIdle(session: FakeSession, timeoutMs: number): Promise<void> {
	if (session.status === "idle") return Promise.resolve();
	return new Promise<void>((resolve, reject) => {
		const timer = setTimeout(() => {
			unsub();
			reject(new Error(`Timeout waiting for session ${session.id} to become idle`));
		}, timeoutMs);
		const unsub = session.rpcClient.onEvent((event: any) => {
			if (event.type === "agent_end") {
				clearTimeout(timer);
				unsub();
				resolve();
			}
		});
	});
}

async function captureResumePromptForRestoredReviewer(opts: { restoreStartupWasStreaming: boolean }): Promise<string[]> {
	const stateDir = fs.mkdtempSync(path.join(os.tmpdir(), "verification-restart-resume-prompt-"));
	initVerificationAuthorSidecar(stateDir);
	const sessionId = opts.restoreStartupWasStreaming ? "restart-interrupted-reviewer" : "ordinary-idle-reviewer";
	const prompts: string[] = [];
	let harness: VerificationHarness;
	try {
		const fakeSession = {
			id: sessionId,
			status: "idle",
			nonInteractive: true,
			restoreStartupWasStreaming: opts.restoreStartupWasStreaming,
			rpcClient: {
				onEvent: (_fn: (event: any) => void) => () => {},
				waitForReady: async () => {},
				prompt: async (text: string) => {
					prompts.push(text);
					const resolver = (harness as any).pendingResults.get(sessionId);
					resolver?.({ verdict: true, summary: "Continuation completed." });
					return { success: true };
				},
				async promptWhenReady(text: string) {
					return this.prompt(text);
				},
			},
		};
		const sessionManager = {
			getSession: () => fakeSession,
			waitForIdle: () => new Promise<void>(() => {}),
			waitForStreaming: () => Promise.resolve(),
			terminateSession: () => Promise.resolve(),
		} as any;
		const gateStore = {
			updateSignalVerification: () => {},
			updateGateStatus: () => {},
			getGate: () => undefined,
			getGatesForGoal: () => [],
		} as any;
		harness = new VerificationHarness(
			stateDir,
			gateStore,
			() => {},
			{ get: () => undefined, getAll: () => [] } as any,
			undefined,
			sessionManager,
			{ registerReviewerSession: () => {}, unregisterReviewerSession: () => {} } as any,
		) as any;

		await (harness as any)._tryResumeFromSession(
			{ goalId: "goal-1", gateId: "gate-1", signalId: "signal-1" },
			{ name: "Restart resume review", type: "llm-review", status: "running", startedAt: Date.now() - 1_000, sessionId },
		);
		return prompts;
	} finally {
		fs.rmSync(stateDir, { recursive: true, force: true });
	}
}

async function runRestartContinuationFallback(opts: { jsonValidationErrorDuringContinuation?: boolean } = {}) {
	const stateDir = fs.mkdtempSync(path.join(os.tmpdir(), "verification-post-continuation-fallback-"));
	initVerificationAuthorSidecar(stateDir);
	const sessionId = "restart-continuation-fallback-reviewer";
	const prompts: string[] = [];
	const calls: string[] = [];
	const listeners: Array<(event: any) => void> = [];
	let harness: VerificationHarness;
	try {
		const fakeSession = {
			id: sessionId,
			status: "idle",
			nonInteractive: true,
			restoreStartupWasStreaming: true,
			lastTurnErrored: false,
			lastTurnErrorMessage: "",
			rpcClient: {
				onEvent: (fn: (event: any) => void) => {
					listeners.push(fn);
					return () => {
						const i = listeners.indexOf(fn);
						if (i >= 0) listeners.splice(i, 1);
					};
				},
				waitForReady: async () => {},
				prompt: async (text: string) => {
					return fakeSession.rpcClient.promptWhenReady(text);
				},
				promptWhenReady: async (text: string) => {
					prompts.push(text);
					calls.push(`prompt:${prompts.length}`);
					if (prompts.length === 2) {
						const resolver = (harness as any).pendingResults.get(sessionId);
						resolver?.({ verdict: true, summary: "Fallback reminder completed." });
					}
					return { success: true };
				},
			},
		};
		const sessionManager = {
			getSession: () => fakeSession,
			waitForStreaming: async () => {
				calls.push(`waitForStreaming:${prompts.length}`);
				fakeSession.status = "streaming";
				if (prompts.length === 1 && opts.jsonValidationErrorDuringContinuation) {
					for (const listener of [...listeners]) {
						listener({
							type: "tool_execution_end",
							isError: true,
							result: "Validation failed for tool verification_result: Expected property name in JSON at position 2",
						});
					}
				}
			},
			waitForIdle: async () => {
				calls.push(`waitForIdle:${prompts.length}`);
				fakeSession.status = "idle";
			},
			terminateSession: async () => {
				calls.push(`terminate:${prompts.length}`);
			},
		} as any;
		const gateStore = {
			updateSignalVerification: () => {},
			updateGateStatus: () => {},
			getGate: () => undefined,
			getGatesForGoal: () => [],
		} as any;
		harness = new VerificationHarness(
			stateDir,
			gateStore,
			() => {},
			{ get: () => undefined, getAll: () => [] } as any,
			undefined,
			sessionManager,
			{ registerReviewerSession: () => {}, unregisterReviewerSession: () => {} } as any,
		) as any;

		const result = await (harness as any)._tryResumeFromSession(
			{ goalId: "goal-1", gateId: "gate-1", signalId: "signal-1" },
			{ name: "Restart resume review", type: "llm-review", status: "running", startedAt: Date.now() - 1_000, sessionId },
		);
		return { prompts, calls, result };
	} finally {
		fs.rmSync(stateDir, { recursive: true, force: true });
	}
}

