describe("verification reminder race — Bug 2 (resumed reviewer terminated early)", () => {
	it("restart-interrupted restored idle nonInteractive reviewer gets a restart-aware continuation prompt first", async () => {
		const prompts = await captureResumePromptForRestoredReviewer({ restoreStartupWasStreaming: true });
		const firstPrompt = prompts[0] ?? "";

		assert.equal(prompts.length, 1, `RESTART_RESUME_REGRESSION: expected exactly one first post-restart prompt, got ${prompts.length}: ${JSON.stringify(prompts)}`);
		const firstBasePrompt = assertSingleSystemPrefix(firstPrompt, "restart-aware continuation");
		assert.equal(
			firstBasePrompt,
			VERIFICATION_RESTART_RESUME_PROMPT,
			`RESTART_RESUME_REGRESSION: provider prefixing must retain the exact restart-aware continuation text. prompt=${JSON.stringify(firstPrompt)}`,
		);
		assert.notEqual(
			firstBasePrompt,
			VERIFICATION_RESULT_REMINDER,
			`RESTART_RESUME_REGRESSION: restored idle nonInteractive verifier with restoreStartupWasStreaming=true received VERIFICATION_RESULT_REMINDER as the first post-restart prompt instead of restart-aware continuation instructions. prompt=${JSON.stringify(firstPrompt)}`,
		);
		assert.match(
			firstBasePrompt,
			/restart|restarted/i,
			`RESTART_RESUME_REGRESSION: restart-aware continuation prompt must mention that infrastructure restarted mid-turn. prompt=${JSON.stringify(firstPrompt)}`,
		);
		assert.match(
			firstBasePrompt,
			/transcript|context/i,
			`RESTART_RESUME_REGRESSION: restart-aware continuation prompt must tell the reviewer to use preserved transcript/context. prompt=${JSON.stringify(firstPrompt)}`,
		);
		assert.match(
			firstBasePrompt,
			/continue/i,
			`RESTART_RESUME_REGRESSION: restart-aware continuation prompt must tell the reviewer to continue the interrupted review. prompt=${JSON.stringify(firstPrompt)}`,
		);
		assert.match(
			firstBasePrompt,
			/verification_result[\s\S]*complete|complete[\s\S]*verification_result/i,
			`RESTART_RESUME_REGRESSION: restart-aware continuation prompt must reserve verification_result for when review is complete. prompt=${JSON.stringify(firstPrompt)}`,
		);
	});

	it("ordinary restored idle nonInteractive reviewer still gets the idle-without-result reminder", async () => {
		const prompts = await captureResumePromptForRestoredReviewer({ restoreStartupWasStreaming: false });

		assert.deepEqual(
			prompts,
			[modelFacingSystemPrompt(VERIFICATION_RESULT_REMINDER)],
			`Ordinary non-restart idle-without-result verifier should receive exactly one system prefix followed by VERIFICATION_RESULT_REMINDER. prompts=${JSON.stringify(prompts)}`,
		);
	});

	it("post-restart continuation that goes idle without a result falls back to the normal reminder with a fair turn", async () => {
		const { prompts, calls, result } = await runRestartContinuationFallback();

		assert.deepEqual(
			prompts,
			[
				modelFacingSystemPrompt(VERIFICATION_RESTART_RESUME_PROMPT),
				modelFacingSystemPrompt(VERIFICATION_RESULT_REMINDER),
			],
			`Restart-aware continuation and fallback reminder must each reach the provider with exactly one system prefix and unchanged base text. prompts=${JSON.stringify(prompts)}`,
		);
		assert.deepEqual(
			calls.slice(0, 6),
			["prompt:1", "waitForStreaming:1", "waitForIdle:1", "prompt:2", "waitForStreaming:2", "waitForIdle:2"],
			`Fallback reminder must use the same promptWhenReady + waitForStreaming + idle wait sequence before completion/failure. calls=${JSON.stringify(calls)}`,
		);
		assert.equal(result.passed, true);
		assert.equal(result.output, "Fallback reminder completed.");
		assert.ok(calls.includes("terminate:2"), `resumed reviewer should be terminated only after the fallback turn resolves. calls=${JSON.stringify(calls)}`);
	});

	it("post-restart continuation JSON glitch falls back to JSON retry instead of another restart prompt", async () => {
		const { prompts, calls, result } = await runRestartContinuationFallback({ jsonValidationErrorDuringContinuation: true });

		const continuationBase = assertSingleSystemPrefix(prompts[0] ?? "", "restart JSON-glitch continuation");
		const fallbackBase = assertSingleSystemPrefix(prompts[1] ?? "", "restart JSON-glitch fallback");
		assert.equal(continuationBase, VERIFICATION_RESTART_RESUME_PROMPT);
		assert.notEqual(fallbackBase, VERIFICATION_RESTART_RESUME_PROMPT, "restart-aware continuation prompt must not be reused after the first post-restart turn");
		assert.notEqual(fallbackBase, VERIFICATION_RESULT_REMINDER, "a validation error during the continuation turn should use the targeted JSON retry fallback");
		assert.match(fallbackBase, /Validation failed for tool|Expected property name in JSON/i);
		assert.deepEqual(
			calls.slice(0, 6),
			["prompt:1", "waitForStreaming:1", "waitForIdle:1", "prompt:2", "waitForStreaming:2", "waitForIdle:2"],
			`JSON fallback must still get a fair promptWhenReady + waitForStreaming + idle wait turn. calls=${JSON.stringify(calls)}`,
		);
		assert.equal(result.passed, true);
	});

	it("sleep or Wi-Fi disconnect resumes the same reviewer instead of surfacing a transient rerun", async () => {
		const { prompts, calls, result } = await runNetworkDisconnectRecovery();

		assert.deepEqual(prompts, [], "Infrastructure disconnect recovery should retry/continue the existing reviewer, not send a reminder or start a fresh prompt path");
		assert.deepEqual(
			calls.slice(0, 3),
			["retryLastPrompt:auto", "waitForStreaming", "waitForIdle"],
			`Sleep/Wi-Fi disconnect should get one continuation retry and a fair streaming+idle turn before teardown/rerun. calls=${JSON.stringify(calls)}`,
		);
		assert.equal(result.passed, true);
		assert.equal(result.output, "Recovered after network disconnect.");
		assert.ok(calls.includes("terminateSession"), "session cleanup should happen after the continued reviewer returns a result");
	});

	it("waitForStreaming resolves when an idle session transitions to streaming", async () => {
		const session = new FakeSession("rv-1");

		assert.equal(session.status, "idle");
		const promise = waitForStreaming(session, 1_000);

		let resolved = false;
		promise.then(() => { resolved = true; });

		// Prove the idle session does not resolve before the event arrives.
		await Promise.resolve();
		assert.equal(resolved, false, "should still be waiting before agent_start");

		// The transition itself, not a wall-clock timeout, should resolve the wait.
		session.startTurn();
		await promise;
		assert.equal(resolved, true, "should resolve after agent_start");
		assert.equal(session.status, "streaming");
	});

	it("waitForStreaming resolves immediately if already streaming", async () => {
		const session = new FakeSession("rv-2");
		session.status = "streaming";

		await waitForStreaming(session, 1_000);
	});

	it("waitForStreaming rejects on timeout if no agent_start arrives", async () => {
		const session = new FakeSession("rv-3");

		await assert.rejects(() => waitForStreaming(session, 100), /Timeout/);
	});

	/**
	 * The core regression — this is the exact fragment from
	 * `_tryResumeFromSession` after the reminder is dispatched. Without the
	 * `waitForStreaming` gate, the race resolves `idle` immediately (because
	 * the resumed session is in `idle` status when the reminder fires) and
	 * the harness would declare failure and terminate the session — ~46ms
	 * is what was observed in production. With the fix, the race only
	 * starts after agent_start, giving the agent the full waitForIdle
	 * timeout window to respond.
	 */
	it("reminder-then-race gives the agent time to respond after the reminder", async () => {
		const session = new FakeSession("rv-4");

		// Mimic the harness's resultPromise: a deferred that the verification_result
		// tool would resolve. Stays unresolved here — we only care that the race
		// doesn't resolve the `idle` branch instantly.
		let _resolveResult: ((v: any) => void) = () => {};
		const resultPromise = new Promise<any>((res) => { _resolveResult = res; });
		void _resolveResult;

		// 1. Dispatch the reminder (fire-and-forget on RPC).
		await session.rpcClient.prompt();

		// 2. Schedule the agent to start its turn 50ms after the reminder.
		setTimeout(() => session.startTurn(), 50);

		// 3. THE FIX: wait for the agent to start streaming before racing.
		const reminderDispatchedAt = Date.now();
		await waitForStreaming(session, 10_000).catch(() => {});

		// 4. Now race resultPromise vs waitForIdle(2s).
		const racePromise = Promise.race([
			resultPromise.then((r: any) => ({ type: "result" as const, ...r })),
			waitForIdle(session, 2_000).then(() => ({ type: "idle" as const })),
		]);

		// Without the fix, the race would resolve `idle` synchronously because
		// the session was idle at the moment the harness called waitForIdle.
		// With the fix, we waited until the agent started its turn. Now the
		// race only resolves when the agent ends — so 1 second after dispatch,
		// there should be NO resolution yet (the agent is still streaming).
		const wait = new Promise<"pending">((res) => setTimeout(() => res("pending"), 1_000));
		const outcome = await Promise.race([racePromise, wait]);
		const elapsed = Date.now() - reminderDispatchedAt;

		assert.equal(
			outcome, "pending",
			`race should still be pending 1s after reminder (was: ${typeof outcome === "object" ? JSON.stringify(outcome) : outcome}, elapsed: ${elapsed}ms)`,
		);

		// Cleanup so waitForIdle's timer doesn't keep the test alive.
		session.endTurn();
		await racePromise;
	});

	/**
	 * Negative control — demonstrates the original bug. When the reminder
	 * is dispatched against an idle session and the harness goes straight to
	 * the race (skipping `waitForStreaming`), `waitForIdle` resolves
	 * synchronously because the session is still idle. The race then resolves
	 * `idle` instantly even though the agent has not yet processed the
	 * reminder. This is what the production fix prevents.
	 */
	it("control: race without waitForStreaming resolves idle instantly (the original bug)", async () => {
		const session = new FakeSession("rv-5");
		const resultPromise = new Promise<any>(() => {});

		await session.rpcClient.prompt();
		setTimeout(() => session.startTurn(), 50);

		const t0 = Date.now();
		// NO waitForStreaming — straight to the race.
		const outcome = await Promise.race([
			resultPromise.then((r: any) => ({ type: "result" as const, ...r })),
			waitForIdle(session, 2_000).then(() => ({ type: "idle" as const })),
		]);
		const elapsed = Date.now() - t0;

		assert.equal(outcome.type, "idle", "control case: race resolves idle");
		assert.ok(elapsed < 50, `control case: race resolves ~immediately (${elapsed}ms) — this is the bug`);

		// Cleanup the queued startTurn timer.
		await new Promise((r) => setTimeout(r, 60));
	});

	it("reminder failure/termination waits for the reminder turn to actually start", async () => {
		const session = new FakeSession("rv-6");
		const calls: string[] = [];
		const resultPromise = new Promise<any>(() => {});
		let terminated = false;

		async function reminderThenFailOrTerminate() {
			calls.push("prompt:reminder");
			await session.rpcClient.prompt();
			calls.push("waitForStreaming");
			await waitForStreaming(session, 1_000).catch(() => {});
			calls.push("race:start");
			const outcome = await Promise.race([
				resultPromise.then((r: any) => ({ type: "result" as const, ...r })),
				waitForIdle(session, 2_000).then(() => ({ type: "idle" as const })),
			]);
			if (outcome.type === "idle") {
				calls.push("fail:idle-after-reminder");
				terminated = true;
				calls.push("terminateSession");
			}
		}

		const run = reminderThenFailOrTerminate();
		setTimeout(() => {
			calls.push("agent_start");
			session.startTurn();
		}, 25);

		await new Promise((resolve) => setTimeout(resolve, 100));
		assert.deepEqual(
			calls,
			["prompt:reminder", "waitForStreaming", "agent_start", "race:start"],
			`Reminder path must wait for agent_start before starting the idle race. calls=${JSON.stringify(calls)}`,
		);
		assert.equal(
			terminated,
			false,
			`Reviewer must not be failed/terminated while the reminder turn is still streaming. calls=${JSON.stringify(calls)}`,
		);

		session.endTurn();
		await run;
		assert.equal(terminated, true);
		assert.ok(
			calls.indexOf("terminateSession") > calls.indexOf("race:start"),
			`Termination should happen only after the post-reminder idle window. calls=${JSON.stringify(calls)}`,
		);
	});

	it("resumed idle reviewers are reminded immediately while busy reviewers get the resolved turn allowance", () => {
		const source = fs.readFileSync(path.join(process.cwd(), "src/server/agent/verification-harness.ts"), "utf8");
		const start = source.indexOf("private async _tryResumeFromSession");
		assert.ok(start >= 0, "_tryResumeFromSession should exist");
		const reminder = source.indexOf("No verification_result from resumed session", start);
		assert.ok(reminder > start, "resumed reminder path should exist");
		const preReminder = source.slice(start, reminder);

		assert.match(
			preReminder,
			/const idleResult = session\.status === "idle"\s*\? \(\{ type: "idle" as const \}\)\s*:\s*await this\.waitForReviewTurn\(step\.sessionId, resultPromise, timeoutMs\);/,
			"A restored reviewer that is already idle must go straight to the reminder; a busy reviewer must wait through the shared review-turn helper.",
		);
		assert.match(
			preReminder,
			/const timeoutMs = timeoutSec \* 1000;[\s\S]*await this\.waitForReviewTurn\(step\.sessionId, resultPromise, timeoutMs\)/,
			"Busy resumed reviewers should receive the resolved per-step allowance rather than a hardcoded restart window.",
		);
	});

	it("resume boot surfaces nonInteractive reviewers with no active verification context", () => {
		const source = fs.readFileSync(path.join(process.cwd(), "src/server/agent/verification-harness.ts"), "utf8");
		const resumeStart = source.indexOf("async resumeInterruptedVerifications(): Promise<void>");
		assert.ok(resumeStart >= 0, "resumeInterruptedVerifications should exist");
		const findStepStart = source.indexOf("private async _resumeOneVerification", resumeStart);
		assert.ok(findStepStart > resumeStart, "resumeInterruptedVerifications should be bounded");
		const resumeBody = source.slice(resumeStart, findStepStart);

		assert.doesNotMatch(
			resumeBody,
			/if \(persisted\.length === 0\) return;/,
			"Boot resume must not silently return when there is no active verification context; orphaned nonInteractive reviewers must be surfaced deterministically.",
		);
		assert.match(
			resumeBody,
			/await this\._surfaceOrphanedNonInteractiveReviewers\(\);[\s\S]*if \(persisted\.length === 0\)/,
			"Boot resume must surface orphaned nonInteractive reviewer sessions before any early return.",
		);
		assert.match(
			source,
			/listOrphanedNonInteractiveSessions\(\)/,
			"Orphan surfacing should use SessionManager's active-verification-aware orphan detector.",
		);
	});

	it("orphan surfacing is not blocked behind unrelated running verification resume", async () => {
		const stateDir = fs.mkdtempSync(path.join(os.tmpdir(), "verification-orphan-surface-"));
		try {
			fs.writeFileSync(path.join(stateDir, "active-verifications.json"), JSON.stringify({
				verifications: [{
					goalId: "goal-1",
					gateId: "gate-1",
					signalId: "signal-1",
					overallStatus: "running",
					startedAt: Date.now(),
					steps: [{
						name: "Busy review",
						type: "llm-review",
						status: "running",
						startedAt: Date.now(),
						sessionId: "active-reviewer",
					}],
				}],
			}, null, 2));

			let orphanListCalls = 0;
			const fakeSession = {
				status: "streaming",
				rpcClient: { onEvent: () => () => {} },
			};
			const sessionManager = {
				getSession: () => fakeSession,
				waitForIdle: () => new Promise<void>(() => {}),
				waitForStreaming: () => Promise.resolve(),
				terminateSession: () => Promise.resolve(),
				listOrphanedNonInteractiveSessions: async () => {
					orphanListCalls += 1;
					return [{ id: "orphan-reviewer", title: "Orphan reviewer", createdAt: Date.now() }];
				},
			} as any;
			const gateStore = {
				updateSignalVerification: () => {},
				updateGateStatus: () => {},
				getGate: () => undefined,
				getGatesForGoal: () => [],
			} as any;
			const harness = new VerificationHarness(
				stateDir,
				gateStore,
				() => {},
				{ get: () => undefined, getAll: () => [] } as any,
				undefined,
				sessionManager,
				{ registerReviewerSession: () => {}, unregisterReviewerSession: () => {} } as any,
			);

			void harness.resumeInterruptedVerifications();
			await new Promise((resolve) => setTimeout(resolve, 50));

			assert.equal(
				orphanListCalls,
				1,
				"orphan reviewer surfacing must run promptly before an unrelated running verification can block in waitForIdle",
			);
		} finally {
			fs.rmSync(stateDir, { recursive: true, force: true });
		}
	});

	it("live llm-review checks errored-turn recovery after post-reminder idle before declaring the reminder ignored", () => {
		const source = fs.readFileSync(path.join(process.cwd(), "src/server/agent/verification-harness.ts"), "utf8");
		const livePathStart = source.indexOf("private async runLlmReviewViaSession");
		assert.ok(livePathStart >= 0, "runLlmReviewViaSession should exist");

		const hardFailure = source.indexOf("output: \"Agent did not call verification_result after reminder.\"", livePathStart);
		assert.ok(hardFailure >= 0, "live post-reminder ignored-reminder failure should exist");

		const resultRace = source.lastIndexOf("const result2 = await this.waitForReviewTurn(sessionId, resultPromise, timeoutMs)", hardFailure);
		assert.ok(resultRace > livePathStart, "should find live post-reminder review-turn wait");
		const postReminderIdlePath = source.slice(resultRace, hardFailure);

		assert.match(
			postReminderIdlePath,
			/const postReminderRecovery = await this\.waitForReviewerErroredTurnRecovery\(sessionId, resultPromise, timeoutMs, step\.name\);/,
			"Post-reminder idle must call errored-turn recovery before ignored-reminder failure.",
		);
		assert.match(
			postReminderIdlePath,
			/postReminderRecovery\.type === "result"[\s\S]*postReminderRecovery\.summary/,
			"Post-reminder recovery must return a verification_result that arrives during auto-retry.",
		);
		assert.match(
			postReminderIdlePath,
			/postReminderRecovery\.type === "errored"[\s\S]*postReminderRecovery\.output/,
			"Post-reminder recovery exhaustion must surface the retryable runtime error instead of ignored-reminder text.",
		);
	});
});
